1	const PROCESSING_FEE_G = 5;
2	const BLOCK_SIZE = 3;
3	const BLOCK_PRICE_G = 60;
4	const COMPONENT_UNIT_PRICE_G = 25;
5	
6	const MAIN_ITEM_BASE: Record<string, number> = {
7	  sword: 100,
8	  amulet: 60,
9	  staff: 80,
10	  potion: 40,
11	};
12	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
13	
14	type Item = { type: string; cursed?: boolean; enchantment?: number };
15	type Scenario = {
16	  customer: { yearsWithMHPCO: number };
17	  steps: Array<{ op: "quote"; items: Item[] }>;
18	};
19	
20	const sum = (numbers: number[]): number =>
21	  numbers.reduce((acc, n) => acc + n, 0);
22	
23	const componentBaseForGroup = (count: number): number =>
24	  count === BLOCK_SIZE ? BLOCK_PRICE_G : count * COMPONENT_UNIT_PRICE_G;
25	
26	const componentBaseTotal = (componentItems: Item[]): number => {
27	  const counts = new Map<string, number>();
28	  for (const item of componentItems) {
29	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
30	  }
31	  return sum([...counts.values()].map(componentBaseForGroup));
32	};
33	
34	const mainItemBase = (item: Item): number => MAIN_ITEM_BASE[item.type] ?? 0;
35	
36	const CURSE_RATE = 0.5;
37	const HIGH_ENCHANTMENT_RATE = 0.3;
38	const HIGH_ENCHANTMENT_THRESHOLD = 5;
39	
40	const isCursed = (item: Item): boolean => item.cursed === true;
41	const isHighlyEnchanted = (item: Item): boolean =>
42	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
43	
44	const mainItemModifiers = (item: Item): number => {
45	  const base = mainItemBase(item);
46	  const rate =
47	    (isCursed(item) ? CURSE_RATE : 0) +
48	    (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_RATE : 0);
49	  return base * rate;
50	};
51	
52	const firstInsuranceSurcharge = (policyBase: number): number => policyBase / 10;
53	
54	const loyaltyDiscount = (policyBase: number, yearsWithMHPCO: number): number =>
55	  yearsWithMHPCO >= 2 ? policyBase * 0.2 : 0;
56	
57	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
58	
59	const followUpDiscount = (policyBase: number, isFollowUp: boolean): number =>
60	  isFollowUp ? policyBase * 0.15 : 0;
61	
62	const quotePremium = (items: Item[], yearsWithMHPCO: number, isFollowUp: boolean): number => {
63	  const mainItems = items.filter((i) => !isComponent(i));
64	  const componentItems = items.filter(isComponent);
65	  const policyBase = sum(mainItems.map(mainItemBase)) + componentBaseTotal(componentItems);
66	  const itemModifiersTotal = sum(mainItems.map(mainItemModifiers));
67	  const surcharges = firstInsuranceSurcharge(policyBase);
68	  const discounts = loyaltyDiscount(policyBase, yearsWithMHPCO) + followUpDiscount(policyBase, isFollowUp);
69	  return Math.ceil(policyBase + itemModifiersTotal + surcharges - discounts + PROCESSING_FEE_G);
70	};
71	
72	export const runScenario = (scenario: unknown): unknown => {
73	  const s = scenario as Scenario;
74	  let quoteCount = 0;
75	  const results = s.steps.map((step) => {
76	    const isFollowUp = quoteCount > 0;
77	    quoteCount += 1;
78	    return { premium: quotePremium(step.items, s.customer.yearsWithMHPCO, isFollowUp) };
79	  });
80	  return { results };
81	};
